import pandas as pd                                                                               
from sklearn.decomposition import PCA
from sklearn.preprocessing import StandardScaler                                                  
                  
# Load the feature matrix generated by feature_engineering.py
try:
    feature_df = pd.read_csv("./feature_matrix.csv")
except FileNotFoundError:                                                                         
    print("Error: 'feature_matrix.csv' not found. Please run feature_engineering.py first to generate it.")                                                                                    
    exit()      

# Separate features from the target variable (if it exists in the output)                         
# Assuming 'fire_occurrence_label' is the target column, adjust if necessary
# If the target is not yet created, you might need to run a different script                      
# or create it based on the 'annual_fire_count' in feature_df.
if 'fire_occurrence_label' in feature_df.columns:                                                 
    X = feature_df.drop(columns=['zip', 'year', 'fire_occurrence_label'])
    target = feature_df['fire_occurrence_label']                                                  
else:           
    # If the target column doesn't exist, we'll perform PCA on all columns except identifiers     
    # This might be useful for exploratory analysis before a target is defined or if
    # PCA is purely for dimensionality reduction before QML encoding.                             
    print("Warning: 'fire_occurrence_label' not found. Performing PCA on all available features (excluding zip and year).")                                                                       
    # Identify potential identifier columns to exclude
    identifier_cols = ['zip', 'year']                                                             
    feature_cols = [col for col in feature_df.columns if col not in identifier_cols]
    X = feature_df[feature_cols]


# Standardize the features: PCA is sensitive to scale
scaler = StandardScaler()
X_scaled = scaler.fit_transform(X)

# Determine the number of components for PCA.                                                     
# For QML, we aim for 8-12 features. Let's target 10 components.
# DECREASED IT TO 5, WHICH STILL COVERS 90% OF VARIANCE!!
n_components = 5                                                                               
if X_scaled.shape[1] < n_components:
    n_components = X_scaled.shape[1]                                                              
    print(f"Warning: Number of features ({X_scaled.shape[1]}) is less than target n_components ({10}). Using {n_components} components.")                                                        
                
                                                                                                
# Apply PCA     
pca = PCA(n_components=n_components)
principal_components = pca.fit_transform(X_scaled)

# Create a DataFrame for the principal components
pca_df = pd.DataFrame(data=principal_components, columns=[f'PC{i+1}' for i in
range(n_components)])                                                                             

# Combine with original identifiers and target if available                                       
# Add zip and year back if they were in the original dataframe
if 'zip' in feature_df.columns:
    pca_df.insert(0, 'zip', feature_df['zip'])
if 'year' in feature_df.columns:
    pca_df.insert(1, 'year', feature_df['year'])
if 'fire_occurrence_label' in feature_df.columns:                                                 
    pca_df['fire_occurrence_label'] = target
                                                                                                
# Display the PCA results
print("\nPCA Applied. Resulting DataFrame shape:", pca_df.shape)
print("\nPrincipal Components (first 5 rows):")                                                   
print(pca_df.head())
                                                                                                
# Explained variance ratio
print(f"\nTotal variance explained by {n_components} components: {pca_df.drop(columns=['zip', 
'year'], errors='ignore').apply(lambda col:                                                       
pca.explained_variance_ratio_[pca_df.columns.get_loc(col.name) - (2 if 'zip' in pca_df.columns and
'year' in pca_df.columns else (1 if 'zip' in pca_df.columns or 'year' in pca_df.columns else     
0))]).sum():.4f}")

# You can save the PCA-transformed data
pca_df.to_csv("pca_features.csv", index=False)
print("\nPCA results saved to 'pca_features.csv'")